    while (t--) {
        int n;
        scanf("%d", &n); // Read the size of the array
        int arr[n]; // Declare the array
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]); // Read the array elements
        }

        int ans[n]; // Declare the answer array
        ans[n-1] = 1; // Initialize the last element of ans
        for (int i = n - 2; i >= 0; i--) {
            // Check the sign of current and next elements
            if ((arr[i] > 0 && arr[i + 1] < 0) || (arr[i] < 0 && arr[i + 1] > 0)) {
                ans[i] = ans[i + 1] + 1; // Increment count if signs are different
            } else {
                ans[i] = 1; // Reset count if signs are the same
            }
        }

        // Print the answer array
        for (int i = 0; i < n; i++) {
            printf("%d ", ans[i]);
        }
        printf("\n"); // Print a new line after each test case
    }

    return 0; // Indicate successful completion
}

