import java.util.*;

class Codechef {
    public static void main(String[] args) throws java.lang.Exception {
        Scanner scanner = new Scanner(System.in);

        int t = scanner.nextInt(); // Read number of test cases
        for (int test = 0; test < t; test++) {
            int n = scanner.nextInt(); // Read size of the array
            int[] arr = new int[n]; // Initialize array
            for (int i = 0; i < n; i++) {
                arr[i] = scanner.nextInt(); // Read array elements
            }

            int[] ans = new int[n]; // Initialize answer array
            ans[n - 1] = 1; // Last element is always 1
            for (int i = n - 2; i >= 0; i--) {
                // Check if signs of arr[i] and arr[i + 1] are different
                if ((arr[i] > 0 && arr[i + 1] < 0) || (arr[i] < 0 && arr[i + 1] > 0)) {
                    ans[i] = ans[i + 1] + 1; // Increment based on previous value
                } else {
                    ans[i] = 1; // Reset to 1 if signs are the same
                }
            }

            // Print the result
            for (int item: ans) {
                System.out.print(item + " ");
            }
            System.out.println();
        }

        scanner.close(); // Close the scanner
    }
}

